     9→using mlir::iree_compiler::IREE::Codegen::LoweringConfigAttr;
    10→
    11→namespace mlir::iree_compiler {
    12→
    13→TilingConfig::TilingConfig(IREE::Codegen::LoweringConfigAttr lc)
    14→    : loweringConfig(lc) {
    15→  assert(lc && "Expected a valid lowering config");
    16→
    17→  // Initialize indices to invalid.
    18→  std::fill(tilingLevelToActualLevelMap.begin(),
    19→            tilingLevelToActualLevelMap.end(), InvalidLevel);
    20→
    21→  // Map the tiling levels that are defined in the actual configuration to
    22→  // their corresponding incremental levels. We currently support the following
    23→  // scenarios:
    24→  //   1. [[distribution]]
    25→  //   2. [[distribution], [vector-common-parallel]]
    26→  //   3. [[distribution], [vector-common-parallel], [vector-reduction]]
    27→  //   4. [[distribution], [vector-common-parallel], [vector-reduction],
    28→  //       [vector-inner-parallel]]
    29→  //   5. [[distribution], [cache-parallel], [cache-reduction],
    30→  //       [vector-common-parallel], [vector-reduction],
    31→  //       [vector-inner-parallel]]
    32→  int numTileLevels = loweringConfig.getTilingLevels().size();
    33→  switch (numTileLevels) {
    34→  case 4:
    35→    tilingLevelToActualLevelMap[VectorInnerParallelTiles] = 3;
    36→    [[fallthrough]];
    37→  case 3:
    38→    tilingLevelToActualLevelMap[VectorReductionTiles] = 2;
    39→    [[fallthrough]];
    40→  case 2:
    41→    tilingLevelToActualLevelMap[VectorCommonParallelTiles] = 1;
    42→    [[fallthrough]];
    43→  case 1:
    44→    tilingLevelToActualLevelMap[DistributionTiles] = 0;
    45→    break;
    46→  case MaxNumTileLevels:
    47→    for (int i = 0; i < MaxNumTileLevels; ++i) {
    48→      tilingLevelToActualLevelMap[i] = i;
    49→    }
    50→    break;
    51→  default:
    52→    break;
    53→  }
    54→};
    55→
    56→/// Returns the tiling level that contains the vector dim at `dimPos` (which is
    57→/// an index into the result of `getVectorTileSizes()`).
    58→std::optional<unsigned>
    59→TilingConfig::getTilingLevelForVectorDimPosition(unsigned dimPos) const {
    60→  constexpr std::array vectorTilingLevels{VectorCommonParallelTiles,
    61→                                          VectorReductionTiles,
    62→                                          VectorInnerParallelTiles};
    63→  std::optional<unsigned> foundLevel;
    64→  auto tilingLevels = loweringConfig.getTilingLevels();
    65→  for (TilingLevel level : vectorTilingLevels) {
    66→    auto tilingLevelIndex = tilingLevelToActualLevelMap[level];
    67→    if (tilingLevelIndex != InvalidLevel &&
    68→        tilingLevels[tilingLevelIndex].getSizes()[dimPos] != 0) {
    69→      assert(!foundLevel.has_value() &&
    70→             "expected at most one tile size to be non-zero");
    71→      foundLevel = tilingLevelIndex;
    72→    }
    73→  }
    74→  return foundLevel;
    75→}
    76→
    77→/// Returns the tile size (size + scalability pair) at `index`. The
    78→/// `scalableFlags` can be empty.
    79→static std::pair<int64_t, bool> getTileSizeAtIndex(ArrayRef<int64_t> sizes,
    80→                                                   ArrayRef<bool> scalableFlags,
    81→                                                   unsigned index) {
    82→  return std::make_pair(sizes[index],
    83→                        index < scalableFlags.size() && scalableFlags[index]);
    84→}
    85→
    86→/// Returns the tile sizes of all the vector dimensions, including parallel
    87→/// and reduction dimensions.
    88→SizesAndScalableFlags TilingConfig::getVectorTileSizes() {
    89→  unsigned numDims = getNumDimensions();
    90→  SmallVector<int64_t> vectorSizes(numDims, 0);
    91→  SmallVector<bool> scalableFlags(numDims, false);
    92→  auto tilingLevels = loweringConfig.getTilingLevels();
    93→  for (int dimPos = 0; dimPos < numDims; ++dimPos) {
    94→    auto dimTilingLevel = getTilingLevelForVectorDimPosition(dimPos);
    95→    if (!dimTilingLevel.has_value())
    96→      continue; // The size for this dim is zero in all vector tiling levels.
    97→    std::tie(vectorSizes[dimPos], scalableFlags[dimPos]) = getTileSizeAtIndex(
    98→        tilingLevels[*dimTilingLevel].getSizes(),
    99→        tilingLevels[*dimTilingLevel].getScalableFlags(), dimPos);
   100→  }
   101→  return std::make_pair(vectorSizes, scalableFlags);
   102→}
   103→
   104→/// Returns a new `LoweringConfigAttr`, with the tile sizes of vector
   105→/// dimensions, set to `sizes`, and the corresponding scalability set to
   106→/// `scalableFlags`.
   107→IREE::Codegen::LoweringConfigAttr
   108→TilingConfig::getLoweringConfigWithNewVectorSizes(
   109→    ArrayRef<int64_t> sizes, ArrayRef<bool> scalableFlags) {
   110→  unsigned numDims = getNumDimensions();
   111→  assert(sizes.size() == numDims &&
   112→         "expected `sizes` to match number of dimensions");
   113→  assert((scalableFlags.empty() || scalableFlags.size() == numDims) &&
   114→         "expected `scalableFlags` to match "
   115→         "number of dimensions (or be empty)");
   116→
   117→  // Make a map from tiling levels to vector dims at that level.
   118→  std::array<SmallVector<unsigned, 4>, MaxNumTileLevels> tilingLevelToDimsMap;
   119→  for (unsigned dimPos = 0; dimPos < numDims; ++dimPos) {
   120→    auto tilingLevelIndex = getTilingLevelForVectorDimPosition(dimPos);
   121→    assert((tilingLevelIndex.has_value() || sizes[dimPos] == 0) &&
   122→           "attempting to set vector size for dim with underspecified tiling "
   123→           "level (zero is the only valid tile size)");
   124→    if (tilingLevelIndex.has_value())
   125→      tilingLevelToDimsMap[*tilingLevelIndex].push_back(dimPos);
   126→  }
   127→
   128→  MLIRContext *context = loweringConfig.getContext();
   129→  auto tilingLevels = loweringConfig.getTilingLevels();
   130→  SmallVector<IREE::Codegen::LoweringConfigTilingLevelAttr> newTilingLevelsList(
   131→      tilingLevels.begin(), tilingLevels.end());
   132→
   133→  // For each vector tiling level:
   134→  for (auto [tilingLevelIndex, tilingLevelDims] :
   135→       llvm::enumerate(tilingLevelToDimsMap)) {
   136→    if (tilingLevelDims.empty())
   137→      continue;
   138→    auto level = tilingLevels[tilingLevelIndex];
   139→    SmallVector<int64_t> newSizes(level.getSizes());
   140→    SmallVector<bool> newScalableFlags(level.getScalableFlags());
   141→    newScalableFlags.resize(numDims);
   142→    // 1. Update all the vector sizes within that tiling level.
   143→    for (unsigned dimPos : tilingLevelDims) {
   144→      std::tie(newSizes[dimPos], newScalableFlags[dimPos]) =
   145→          getTileSizeAtIndex(sizes, scalableFlags, dimPos);
   146→    }
   147→    // 2. Then create a new tiling level attribute for that level.
   148→    auto newLevel = IREE::Codegen::LoweringConfigTilingLevelAttr::get(
   149→        context, newSizes, level.getInterchange(), newScalableFlags);
   150→    newTilingLevelsList[tilingLevelIndex] = newLevel;
   151→  }
   152→
   153→  // Create a new `lowering_config` attribute.
   154→  auto newTilingLevels = IREE::Codegen::LoweringConfigTilingLevelsAttr::get(
   155→      context, newTilingLevelsList);
   156→  return IREE::Codegen::LoweringConfigAttr::get(
   157→      context, newTilingLevels, loweringConfig.getNativeVectorSize());
   158→}
   159→
   160→/// Returns a list with the tiling levels that can be fused for this
   161→/// configuration.
   162→SmallVector<int64_t> TilingConfig::getFusableLevels() {
   163→  switch (getNumTilingLevels()) {
   164→  case 0:
   165→    return {};
   166→  case 1:
   167→    // Only distribution level.
   168→    return {0};
   169→  case 3:
   170→    // Only distribution level + vector common parallel levels.
   171→    return {0, 1};
   172→  case 4:
   173→    // Distribution + vector common parallel levels + vector inner parallel
   174→    // levels.
   175→    return {0, 1, 3};
   176→  case 6:
   177→    // Distribution + cache parallel levels.
   178→    return {0, 1, 3, 5};
   179→  default:
   180→    llvm_unreachable("Unexpected number of tiling levels");
   181→  }
   182→}
   183→
   184→/// Returns the actual level in the configuration for this level of tiling.
   185→unsigned TilingConfig::getActualLevel(TilingLevel level) {
   186→  assert(level < InvalidLevel && "Unexpected invalid tiling level");
   187→  unsigned actualLevel = tilingLevelToActualLevelMap[level];
   188→  assert(actualLevel != InvalidLevel &&
   189→         "Searching for unavailable tiling level");
   190→  return actualLevel;
   191→}
   192→
   193→} // namespace mlir::iree_compiler
