    53→// Check if the given linalg op is fused with another op that may result
    54→// in too much shared memory usage.
    55→static bool fusedOpMayUseExtraSharedMemory(linalg::LinalgOp matmul) {
    56→  if (matmul->getNumResults() != 1)
    57→    return true;
    58→
    59→  auto entryPoint = matmul->getParentOfType<mlir::FunctionOpInterface>();
    60→
    61→  auto getResultBits = [](linalg::LinalgOp linalgOp) {
    62→    auto shapedType = llvm::cast<ShapedType>(linalgOp->getResult(0).getType());
    63→    return IREE::Util::getTypeBitWidth(shapedType.getElementType());
    64→  };
    65→  auto matmulResultBits = getResultBits(matmul);
    66→
    67→  bool fusedWithOp = false;
    68→  entryPoint.walk([&](linalg::LinalgOp linalgOp) {
    69→    if (linalgOp == matmul || isMatmulOrBatchMatmul(linalgOp) ||
    70→        isa<linalg::FillOp>(linalgOp)) {
    71→      return WalkResult::advance();
    72→    }
    73→
    74→    if (linalgOp->getNumResults() != 1 ||
    75→        getResultBits(linalgOp) != matmulResultBits) {
    76→      fusedWithOp = true;
    77→      return WalkResult::interrupt();
    78→    }
    79→    return WalkResult::advance();
    80→  });
    81→  return fusedWithOp;
    82→}
