    88→/// Decides the tiling and distribution parameters for one convolution
    89→/// dimension. Returns true if we can succesfully deduce.
    90→///
    91→/// - `inputDim` is the size of the dimension to be distributed.
    92→/// - `residualThreads` is the remaining threads we can distribute.
    93→/// - `residualTilingFactor` indicates the remaining tiling scale factor.
    94→/// - `wgDimSize` will be updated with the decided workgroup dimension size.
    95→/// - `wgTileSize` will be updated with the decided workgroup tile size.
    96→static bool tileConvOneDim(const int64_t inputDim, const bool isInnerMostDim,
    97→                           int vectorSize, int64_t &residualThreads,
    98→                           int64_t &residualTilingFactor, int64_t &wgDimSize,
    99→                           int64_t &wgTileSize) {
   100→  const int64_t lb = isInnerMostDim ? 2 : 1;
   101→  for (int64_t dim = residualThreads; dim >= lb; dim >>= 1) {
   102→    int64_t chosenTileSize = 0;
   103→    if (isInnerMostDim) {
   104→      // Handle `vectorSize` elements per thread for the innermost dimension.
   105→      // We need this for the best utilization of memory.
   106→      chosenTileSize = vectorSize;
   107→      if (inputDim % (dim * chosenTileSize) != 0)
   108→        continue;
   109→    } else {
   110→      for (int64_t t = residualTilingFactor; t >= 1; t >>= 1)
   111→        if (inputDim % (dim * t) == 0) {
   112→          chosenTileSize = t;
   113→          break;
   114→        }
   115→    }
   116→    if (chosenTileSize) {
   117→      wgDimSize = dim;
   118→      wgTileSize = dim * chosenTileSize;
   119→      residualThreads /= dim;
   120→      residualTilingFactor /= chosenTileSize;
   121→      return true;
   122→    }
   123→  }
   124→  return false;
   125→};
   126→
   127→/// Decides the tiling and distribution parameters for two convolution window
   128→/// dimensions to two workgroup dimensions as a square. Returns true if we can
   129→/// succesfully deduce.
   130→static bool tileConvSquare(const int64_t oh, const int64_t ow,
   131→                           int64_t &residualThreads,
   132→                           int64_t &residualTilingFactor,
   133→                           MutableArrayRef<int64_t> wgDimSizes,
   134→                           MutableArrayRef<int64_t> wgTileSizes) {
   135→  assert(wgDimSizes.size() == 2 && wgTileSizes.size() == 2);
   136→
   137→  const unsigned log2Threads = llvm::Log2_64(residualThreads);
   138→  if (oh == ow && residualThreads != 1 && log2Threads % 2 == 0) {
   139→    const int64_t yz = 1ll << (log2Threads / 2);
   140→
   141→    int64_t chosenTileSize = 1ll << (llvm::Log2_64(residualTilingFactor) / 2);
   142→    while (chosenTileSize >= 1 && ow % (yz * chosenTileSize) != 0) {
   143→      chosenTileSize >>= 1;
   144→    }
