   334→/// Given the linalg `op` with `lhsShape` and `rhsShape`, tries to treat as a
   335→/// (batch) matmul like op and deduce the index of the loop corresponding to
   336→/// B/M/N/K dimension respectively. Returns -1 as the index if unable to deduce.
   337→std::tuple<int, int, int, int> getMatmulBMNKIndex(linalg::LinalgOp op,
   338→                                                  int *lastParallelDim) {
   339→  OpOperand *lhs = op.getDpsInputOperand(0);
   340→  OpOperand *rhs = op.getDpsInputOperand(1);
   341→  auto lhsShape = llvm::cast<ShapedType>(lhs->get().getType()).getShape();
   342→  auto rhsShape = llvm::cast<ShapedType>(rhs->get().getType()).getShape();
   343→
   344→  auto lhsLoopIndices =
   345→      llvm::map_to_vector(llvm::seq<int>(0, lhsShape.size()), [&](int i) {
   346→        return op.getMatchingIndexingMap(lhs).getDimPosition(i);
   347→      });
   348→  auto rhsLoopIndices =
   349→      llvm::map_to_vector(llvm::seq<int>(0, rhsShape.size()), [&](int i) {
   350→        return op.getMatchingIndexingMap(rhs).getDimPosition(i);
   351→      });
   352→
   353→  // Figure out what dimension each loop corresponds to.
   354→  int bIndex = -1, mIndex = -1, nIndex = -1, kIndex = -1;
   355→  for (unsigned i = 0; i < op.getNumLoops(); ++i) {
   356→    if (linalg::isReductionIterator(op.getIteratorTypesArray()[i])) {
   357→      kIndex = i;
   358→      continue;
   359→    }
   360→
   361→    const bool inLHS = llvm::is_contained(lhsLoopIndices, i);
   362→    const bool inRHS = llvm::is_contained(rhsLoopIndices, i);
   363→    if (inLHS && inRHS) {
   364→      bIndex = i;
   365→    } else if (inLHS) {
   366→      // For cases where we have two parallel dimensions only accessed by
   367→      // the LHS, treat the outer one of them as the batch dimension.
   368→      if (mIndex >= 0 && bIndex < 0)
   369→        bIndex = mIndex;
   370→      mIndex = i;
   371→    } else if (inRHS) {
   372→      // For cases where we have two parallel dimensions only accessed by
   373→      // the RHS, treat the outer one of them as the batch dimension.
   374→      if (nIndex >= 0 && bIndex < 0)
   375→        bIndex = nIndex;
   376→      nIndex = i;
   377→    }
   378→    if (lastParallelDim)
   379→      *lastParallelDim = i;
   380→  }
   381→
   382→  LLVM_DEBUG({
   383→    llvm::dbgs() << "(B, M, N, K) indices = (" << bIndex << ", " << mIndex
   384→                 << ", " << nIndex << ", " << kIndex << ")\n";
   385→  });
   386→  return {bIndex, mIndex, nIndex, kIndex};
   387→}
